from pathlib import Path
import openpyxl
import re

def verify(workspace_path, external_services_path=None):
    wb_path = Path(workspace_path) / 'benefits.xlsx'
    if not wb_path.exists():
        candidates = list(Path(workspace_path).glob('*benefits*.xlsx'))
        if candidates:
            wb_path = candidates[0]
        else:
            return {'pass': False, 'score': 0.0, 'feedback': 'benefits.xlsx not found in workspace'}
    try:
        wb = openpyxl.load_workbook(wb_path)
        ws = wb.active
        rows = list(ws.iter_rows(values_only=True))
        if len(rows) < 2:
            return {'pass': False, 'score': 0.0, 'feedback': f'Expected at least 2 rows (header + data) in benefits.xlsx, found {len(rows)}'}
        data_rows = [r for r in rows[1:] if any(v is not None for v in r)]
        if len(data_rows) < 1:
            return {'pass': False, 'score': 0.0, 'feedback': 'No data rows found in benefits.xlsx'}
        if len(data_rows) > 1:
            return {'pass': False, 'score': 0.0, 'feedback': f'Expected exactly 1 data row in benefits.xlsx, found {len(data_rows)}'}
        headers = [str(c).strip() if c is not None else '' for c in rows[0]]
        data = data_rows[0]

        def get_val(col_name):
            col_lower = col_name.lower().replace('_', '').replace(' ', '')
            for i, h in enumerate(headers):
                h_norm = h.lower().replace('_', '').replace(' ', '')
                if h_norm == col_lower:
                    if i < len(data):
                        return str(data[i]).strip() if data[i] is not None else ''
            return None

        def currency_eq(val, expected):
            def clean(s):
                return re.sub(r'[\s,$%]', '', str(s).strip())
            return clean(val) == clean(expected)

        def loose_match(val, expected):
            v = val.strip().lower().replace(' ', '').replace(',', '')
            e = expected.strip().lower().replace(' ', '').replace(',', '')
            if v == e:
                return True
            if currency_eq(val, expected):
                return True
            if '%' in expected:
                num = expected.replace('%', '').strip()
                val_clean = val.replace('%', '').strip()
                try:
                    if float(val_clean) == float(num) or float(val_clean) == float(num) / 100:
                        return True
                except:
                    pass
            return False

        def normalize_date(val, expected):
            # Strip time component if present
            val = re.split(r'\s+', val.strip())[0]
            val_parts = re.split(r'[/\-]', val.strip())
            if len(val_parts) == 3 and len(val_parts[0]) == 4:
                val = f'{val_parts[1]}/{val_parts[2]}/{val_parts[0]}'
            return val.lower().replace(' ', '') == expected.lower().replace(' ', '')

        errors = []
        checks = [
            ('Home_Infusion_Covered', 'YES'),
            ('Benefit_Type', 'Medical'),
            ('PA_Required', 'YES'),
            ('PA_Phone', '(800) 555-7221'),
            ('PA_Submission_Email', 'pa@aetna.com'),
            ('Specialty_Pharmacy_Required', 'NO'),
            ('CareIG_Network_Status', 'In-Network'),
            ('Deductible_Individual', '$1,500'),
            ('Deductible_Met_YTD', '$750'),
            ('OOP_Max_Individual', '$5,000'),
            ('OOP_Max_Met_YTD', '$750'),
            ('Coinsurance_Pct', '20%'),
            ('Copay_Amount', '$0'),
            ('Plan_Year_Type', 'Calendar'),
            ('Payer_Type', 'Commercial PPO'),
            ('Nursing_Code_Pref', '99600'),
            ('Coverage_Effective_Date', '01/01/2026'),
            ('Coverage_Term_Date', '12/31/2026'),
            ('BV_Call_Date', '04/02/2026'),
            ('BV_Call_Ref_Number', 'AET-BV-20260402-884471'),
            ('BV_Complete', 'YES'),
        ]
        for col, expected in checks:
            val = get_val(col)
            if val is None:
                errors.append(f'Column {col} not found in benefits.xlsx (headers found: {", ".join(headers[:10])}...)')
                continue
            if not loose_match(val, expected):
                if col == 'PA_Phone':
                    if re.sub(r'\D', '', val) == re.sub(r'\D', '', expected):
                        continue
                if 'Date' in col or 'date' in col:
                    if normalize_date(val, expected):
                        continue
                errors.append(f'Column {col}: expected "{expected}", got "{val}"')

        rep = get_val('BV_Rep_Name')
        if rep is None:
            errors.append('Column BV_Rep_Name not found in benefits.xlsx')
        elif 'marcus' not in rep.lower():
            errors.append(f'BV_Rep_Name expected to contain "Marcus", got "{rep}"')

        log = get_val('Financial_Counseling_Log')
        if log is None:
            errors.append('Column Financial_Counseling_Log not found in benefits.xlsx')
        else:
            if '04/03/2026' not in log and '2026-04-03' not in log and '4/3/2026' not in log:
                errors.append(f'Financial_Counseling_Log missing date 04/03/2026, got: "{log}"')
            if '11:22' not in log:
                errors.append(f'Financial_Counseling_Log missing time 11:22, got: "{log}"')
            if '1639' not in log.replace(' ', '').replace(',', ''):
                errors.append(f'Financial_Counseling_Log missing Est OOP $1,639, got: "{log}"')

        if errors:
            return {'pass': False, 'score': 0.0, 'feedback': 'benefits.xlsx verification failed: ' + '; '.join(errors)}

        return {'pass': True, 'score': 1.0, 'feedback': 'benefits.xlsx data row contains all required values including Home_Infusion_Covered=YES, Benefit_Type=Medical, PA_Required=YES, BV_Rep_Name contains Marcus, Financial_Counseling_Log contains 04/03/2026 11:22 and Est OOP $1,639'}
    except Exception as e:
        return {'pass': False, 'score': 0.0, 'feedback': f'Error reading benefits.xlsx: {e}'}

