def verify(workspace_path, external_services_path=None):
    wb_path = Path(workspace_path) / 'audit_log.xlsx'
    if not wb_path.exists():
        return {'pass': False, 'score': 0.0, 'feedback': 'audit_log.xlsx not found in workspace'}
    try:
        wb = openpyxl.load_workbook(wb_path)
        ws = wb.active
        rows = list(ws.iter_rows(values_only=True))
        if not rows:
            return {'pass': False, 'score': 0.0, 'feedback': 'audit_log.xlsx is empty'}

        def normalize_header(h):
            h = re.sub(r'\s*\(.*?\)$', '', h).strip()        # strip trailing parenthetical
            h = re.sub(r'(?i)date[_/]time', 'Date/Time', h)  # accept Date_Time or Date/Time
            return h

        raw_headers = [str(c).strip() if c is not None else '' for c in rows[0]]
        headers = [normalize_header(h) for h in raw_headers]

        expected_headers = ['Date/Time', 'CASE_ID', 'Action', 'File_Updated', 'Staff_User', 'Result']
        for i, exp in enumerate(expected_headers):
            if i >= len(headers):
                return {'pass': False, 'score': 0.0, 'feedback': f'Missing header at position {i+1}: expected "{exp}"'}
            if headers[i].lower() != exp.lower():
                return {'pass': False, 'score': 0.0, 'feedback': f'Header mismatch at pos {i+1}: expected "{exp}", got "{raw_headers[i]}"'}

        data_rows = [r for r in rows[1:] if any(v is not None for v in r)]
        if len(data_rows) != 5:
            return {'pass': False, 'score': 0.0, 'feedback': f'Expected 5 data rows in audit_log.xlsx, found {len(data_rows)}'}

        expected_rows = [
            {'CASE_ID': 'Vasquez_03151971', 'Action': 'Referral Received', 'File_Updated': 'intake.xlsx', 'Staff_User': 'Teresa Rodriguez', 'Result': 'SUCCESS'},
            {'CASE_ID': 'Vasquez_03151971', 'Action': 'BVS Assigned', 'File_Updated': 'intake.xlsx', 'Staff_User': 'Teresa Rodriguez', 'Result': 'SUCCESS'},
            {'CASE_ID': 'Vasquez_03151971', 'Action': 'BV Complete', 'File_Updated': 'benefits.xlsx', 'Staff_User': 'Teresa Rodriguez', 'Result': 'SUCCESS'},
            {'CASE_ID': 'Vasquez_03151971', 'Action': 'Formulary Stop', 'File_Updated': None, 'Staff_User': 'Teresa Rodriguez', 'Result': 'STOP'},
            {'CASE_ID': 'Vasquez_03151971', 'Action': 'PA Submitted', 'File_Updated': 'auth.xlsx', 'Staff_User': 'Teresa Rodriguez', 'Result': 'SUCCESS'},
        ]

        col_idx = {h.lower(): i for i, h in enumerate(headers)}

        def get(row, col):
            idx = col_idx.get(col.lower())
            if idx is None:
                return None
            v = row[idx]
            return str(v).strip() if v is not None else ''

        for ri, (row, exp) in enumerate(zip(data_rows, expected_rows)):
            for field, expected_val in exp.items():
                actual = get(row, field)
                if expected_val is None:
                    if actual not in ('', 'None', None):
                        return {'pass': False, 'score': 0.0, 'feedback': f'audit_log row {ri+1} field {field}: expected blank, got "{actual}"'}
                else:
                    if actual is None or actual.lower() != expected_val.lower():
                        return {'pass': False, 'score': 0.0, 'feedback': f'audit_log row {ri+1} field {field}: expected "{expected_val}", got "{actual}"'}

        return {'pass': True, 'score': 1.0, 'feedback': 'audit_log.xlsx has correct headers, 5 data rows, all values match expected'}
    except Exception as e:
        return {'pass': False, 'score': 0.0, 'feedback': f'Error reading audit_log.xlsx: {e}'}

